final:
module top_module(
    input [15:0] in,
    input [1:0] ctrl,
    output [15:0] out
);reg [15:0] obf_temp;

always @*
begin
    case (ctrl)
        2'b00: obf_temp = in;
        2'b01: obf_temp = ~in;
        2'b10: obf_temp = {in[13:0], 2'b00};
        2'b11: obf_temp = {2'b00, in[15:2]};
    endcase
end

assign out = obf_temp;

endmodule
